import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Router } from '@angular/router';
import { Observable } from 'rxjs';
import { tap } from 'rxjs/operators';
import { environment } from 'src/environments/environment';
import { AdminLoginRequest, AdminLoginResponse } from './admin.model';

const TOKEN_KEY = 'wedding_admin_token';

@Injectable({ providedIn: 'root' })
export class AuthService {

  private _loggedIn = false;

  constructor(private http: HttpClient, private router: Router) {
    this._loggedIn = !!localStorage.getItem(TOKEN_KEY);
  }

  isLoggedIn(): boolean {
    return this._loggedIn;
  }

  login(req: AdminLoginRequest): Observable<AdminLoginResponse> {
    return this.http
      .post<AdminLoginResponse>(`${environment.apiUrl}/admin/login`, req)
      .pipe(
        tap(res => {
          localStorage.setItem(TOKEN_KEY, res.token);
          this._loggedIn = true;
        })
      );
  }

  logout(): void {
    localStorage.removeItem(TOKEN_KEY);
    this._loggedIn = false;
    this.router.navigate(['/admin']);
  }

  getToken(): string | null {
    return localStorage.getItem(TOKEN_KEY);
  }
}
